import { describe, it, expect, beforeEach } from 'vitest';
import {
  createOrGetToken,
  submitReport,
  getCivicReports,
  getReportById,
  updateReportStatus,
  submitIncident,
  getSafetyIncidents,
  confirmIncident,
  removeIncident,
  createSOSAlert,
  updateSOSAlert,
  getDashboardStats,
  processSMSReport,
  getSMSReports,
} from '../db/mockApi';

describe('createOrGetToken', () => {
  it('creates a new user token', async () => {
    const { data, error } = await createOrGetToken('test-token-abc');
    expect(error).toBeNull();
    expect(data).toHaveProperty('id');
    expect(data.token).toBe('test-token-abc');
    expect(data.display_name).toBe('Community Member');
  });

  it('returns existing user for same token', async () => {
    const { data: first } = await createOrGetToken('test-token-xyz');
    const { data: second } = await createOrGetToken('test-token-xyz');
    expect(first.id).toBe(second.id);
  });
});

describe('submitReport', () => {
  it('creates a civic report', async () => {
    const { data, error } = await submitReport({
      category: 'pothole',
      title: 'Test pothole',
      description: 'Big hole',
      latitude: -25.865,
      longitude: 25.644,
      address: '123 Test St',
      urgency: 'normal',
    });

    expect(error).toBeNull();
    expect(data).toHaveProperty('id');
    expect(data.category).toBe('pothole');
    expect(data.status).toBe('pending');
  });
});

describe('getCivicReports', () => {
  it('returns seeded reports', async () => {
    const { data, error } = await getCivicReports();
    expect(error).toBeNull();
    expect(data.length).toBeGreaterThan(0);
  });

  it('filters by status', async () => {
    const { data } = await getCivicReports({ status: 'pending' });
    data.forEach(r => expect(r.status).toBe('pending'));
  });

  it('filters by category', async () => {
    const { data } = await getCivicReports({ category: 'pothole' });
    data.forEach(r => expect(r.category).toBe('pothole'));
  });
});

describe('getReportById', () => {
  it('returns a specific report', async () => {
    const { data: all } = await getCivicReports();
    const target = all[0];
    const { data, error } = await getReportById(target.id);
    expect(error).toBeNull();
    expect(data.id).toBe(target.id);
  });

  it('returns null for nonexistent id', async () => {
    const { data, error } = await getReportById('nonexistent-id');
    expect(data).toBeNull();
  });
});

describe('updateReportStatus', () => {
  it('updates report status', async () => {
    const { data: all } = await getCivicReports();
    const report = all.find(r => r.status === 'pending');
    if (!report) return; // skip if no pending reports in seed

    const { data, error } = await updateReportStatus(report.id, 'acknowledged', 'We got it');
    expect(error).toBeNull();
    expect(data.status).toBe('acknowledged');
    expect(data.municipality_response).toBe('We got it');
  });
});

describe('submitIncident', () => {
  it('creates a safety incident', async () => {
    const { data, error } = await submitIncident({
      incident_type: 'theft',
      description: 'Test incident',
      latitude: -25.865,
      longitude: 25.644,
    });

    expect(error).toBeNull();
    expect(data).toHaveProperty('id');
    expect(data.incident_type).toBe('theft');
    expect(data.confirmations).toBe(0);
  });
});

describe('getSafetyIncidents', () => {
  it('returns seeded incidents', async () => {
    const { data, error } = await getSafetyIncidents();
    expect(error).toBeNull();
    expect(data.length).toBeGreaterThan(0);
  });

  it('excludes removed incidents', async () => {
    const { data } = await getSafetyIncidents();
    data.forEach(i => expect(i.is_removed).toBe(false));
  });
});

describe('confirmIncident', () => {
  it('confirms an incident', async () => {
    const { data: incidents } = await getSafetyIncidents();
    const incident = incidents[0];

    const { data, error } = await confirmIncident(incident.id, 'user-123', 'confirm');
    expect(error).toBeNull();
    expect(data.success).toBe(true);
  });

  it('prevents double confirmation', async () => {
    const { data: incidents } = await getSafetyIncidents();
    const incident = incidents[0];

    // First confirmation already done above
    const { error } = await confirmIncident(incident.id, 'user-123', 'confirm');
    expect(error).toBe('Already confirmed');
  });
});

describe('createSOSAlert', () => {
  it('creates an SOS alert', async () => {
    const { data, error } = await createSOSAlert({
      latitude: -25.865,
      longitude: 25.644,
      alert_type: 'panic',
    });

    expect(error).toBeNull();
    expect(data).toHaveProperty('id');
    expect(data.status).toBe('active');
  });
});

describe('getDashboardStats', () => {
  it('returns dashboard statistics', async () => {
    const { data, error } = await getDashboardStats();
    expect(error).toBeNull();
    expect(data).toHaveProperty('totalReports');
    expect(data).toHaveProperty('byStatus');
    expect(data).toHaveProperty('resolutionRate');
    expect(data).toHaveProperty('totalIncidents');
    expect(data.totalReports).toBeGreaterThan(0);
  });
});

describe('processSMSReport', () => {
  it('processes a #REPORT SMS', async () => {
    const { data, error } = await processSMSReport('hash-123', '#REPORT pothole on Main Road at Station Road');
    expect(error).toBeNull();
    expect(data.processed).toBe(true);
    expect(data.parsed_category).toBe('pothole');
  });

  it('processes a #SOS SMS', async () => {
    const { data, error } = await processSMSReport('hash-456', '#SOS');
    expect(error).toBeNull();
    expect(data.processed).toBe(true);
  });

  it('handles unparseable messages', async () => {
    const { data, error } = await processSMSReport('hash-789', 'hello world');
    expect(error).toBeNull();
    expect(data.processed).toBe(false);
  });
});

describe('getSMSReports', () => {
  it('returns SMS reports', async () => {
    const { data, error } = await getSMSReports();
    expect(error).toBeNull();
    expect(Array.isArray(data)).toBe(true);
  });
});

import { useState } from 'react';
import { createBusinessProfile } from '../db/powerApi';
import { getCurrentPosition, reverseGeocode } from '../utils/geolocation';
import { showToast } from '../utils/helpers';
import Icon from './Icon';

const BUSINESS_TYPES = [
  { key: 'restaurant', label: 'Restaurant / Food', icon: '🍽️' },
  { key: 'fresh_produce', label: 'Fresh Produce', icon: '🥬' },
  { key: 'guesthouse', label: 'Guesthouse / B&B', icon: '🏠' },
  { key: 'clothing', label: 'Clothing / Retail', icon: '👗' },
  { key: 'other', label: 'Other', icon: '🏪' },
];

export default function BusinessSignup({ userId, onComplete, onClose }) {
  const [step, setStep] = useState(1);
  const [businessName, setBusinessName] = useState('');
  const [businessType, setBusinessType] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [location, setLocation] = useState(null);
  const [alertRadius, setAlertRadius] = useState(2);
  const [loadingLocation, setLoadingLocation] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  async function detectLocation() {
    setLoadingLocation(true);
    try {
      const pos = await getCurrentPosition();
      setLocation(pos);
      const addr = await reverseGeocode(pos.lat, pos.lng);
      setAddress(addr);
    } catch {
      setLocation({ lat: -25.8653, lng: 25.6441 });
      setAddress('Mahikeng CBD');
    }
    setLoadingLocation(false);
  }

  async function handleSubmit() {
    if (!businessName || !businessType || !phone) {
      showToast?.('Please fill in all required fields', 'error');
      return;
    }

    setSubmitting(true);
    try {
      if (!location) await detectLocation();

      const { data, error } = await createBusinessProfile({
        user_token_id: userId,
        business_name: businessName,
        business_type: businessType,
        phone,
        latitude: location?.lat || -25.8653,
        longitude: location?.lng || 25.6441,
        address,
        alert_radius_km: alertRadius,
      });

      if (error) {
        showToast?.(error, 'error');
      } else {
        onComplete(data);
      }
    } catch (err) {
      showToast?.('Registration failed', 'error');
    }
    setSubmitting(false);
  }

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-end justify-center">
      <div className="bg-white rounded-t-3xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-slide-up">
        <div className="px-4 py-4 border-b border-gray-100 sticky top-0 bg-white z-10">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-bold">Register Business</h2>
            <button onClick={onClose} className="p-2">
              <Icon name="close" className="w-5 h-5" />
            </button>
          </div>
          {/* Progress */}
          <div className="flex gap-2 mt-2">
            <div className={`h-1 flex-1 rounded-full ${step >= 1 ? 'bg-civic-500' : 'bg-gray-200'}`}></div>
            <div className={`h-1 flex-1 rounded-full ${step >= 2 ? 'bg-civic-500' : 'bg-gray-200'}`}></div>
          </div>
        </div>

        {/* Step 1: Business Details */}
        {step === 1 && (
          <div className="px-4 py-4 space-y-4">
            <div>
              <label className="text-sm font-medium text-gray-700 mb-1 block">Business Name *</label>
              <input
                type="text"
                value={businessName}
                onChange={(e) => setBusinessName(e.target.value)}
                placeholder="e.g. Mmabatho Spaza Shop"
                className="input"
              />
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700 mb-2 block">Business Type *</label>
              <div className="grid grid-cols-2 gap-2">
                {BUSINESS_TYPES.map(type => (
                  <button
                    key={type.key}
                    onClick={() => setBusinessType(type.key)}
                    className={`py-3 px-3 rounded-xl text-sm font-medium border transition-colors text-left ${
                      businessType === type.key
                        ? 'bg-civic-50 text-civic-700 border-civic-300'
                        : 'border-gray-200 text-gray-500'
                    }`}
                  >
                    {type.icon} {type.label}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700 mb-1 block">Phone Number *</label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="+27 XX XXX XXXX"
                className="input"
              />
              <p className="text-xs text-gray-400 mt-1">For SMS alerts when outages affect your area</p>
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700 mb-1 block">Business Address</label>
              <input
                type="text"
                value={address}
                onChange={(e) => setAddress(e.target.value)}
                placeholder="e.g. 45 Main Road, Mahikeng"
                className="input"
              />
              <button
                onClick={detectLocation}
                disabled={loadingLocation}
                className="text-xs text-civic-600 font-medium mt-1"
              >
                {loadingLocation ? 'Detecting...' : '📍 Use current location'}
              </button>
            </div>

            <button
              onClick={() => {
                if (!businessName || !businessType || !phone) {
                  showToast?.('Please fill in all required fields', 'error');
                  return;
                }
                if (!location) detectLocation();
                setStep(2);
              }}
              className="btn-primary w-full"
            >
              Next: Alert Settings
            </button>
          </div>
        )}

        {/* Step 2: Alert Settings */}
        {step === 2 && (
          <div className="px-4 py-4 space-y-4">
            <div>
              <label className="text-sm font-medium text-gray-700 mb-2 block">Alert Radius</label>
              <p className="text-xs text-gray-400 mb-3">Get notified when outages are reported within this distance</p>
              <div className="grid grid-cols-3 gap-2">
                {[1, 2, 5].map(km => (
                  <button
                    key={km}
                    onClick={() => setAlertRadius(km)}
                    className={`py-3 rounded-xl text-sm font-medium border transition-colors ${
                      alertRadius === km
                        ? 'bg-civic-50 text-civic-700 border-civic-300'
                        : 'border-gray-200 text-gray-500'
                    }`}
                  >
                    {km}km
                  </button>
                ))}
              </div>
            </div>

            <div className="card bg-civic-50 border-civic-200">
              <h4 className="text-sm font-medium text-civic-800 mb-2">Alert Summary</h4>
              <div className="space-y-1 text-xs text-civic-600">
                <p>🏪 {businessName}</p>
                <p>📍 {address || 'Mahikeng'}</p>
                <p>📱 {phone}</p>
                <p>📡 Alert within {alertRadius}km</p>
              </div>
            </div>

            <div className="card bg-gray-50">
              <p className="text-xs text-gray-500">
                You'll receive push notifications and SMS when power outages are reported
                within {alertRadius}km of your business. Alerts include outage type and suggested actions.
              </p>
            </div>

            <div className="flex gap-3">
              <button
                onClick={() => setStep(1)}
                className="btn-outline flex-1"
              >
                Back
              </button>
              <button
                onClick={handleSubmit}
                disabled={submitting}
                className="btn-primary flex-1"
              >
                {submitting ? 'Registering...' : 'Register Business'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { getLearners, getActiveTrips, getTransportRoutes, registerLearner } from '../db/transportApi';
import { getMahikengCenter } from '../utils/geolocation';
import { showToast, timeAgo } from '../utils/helpers';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: new URL('leaflet/marker-icon-2x.png', import.meta.url).href,
  iconUrl: new URL('leaflet/marker-icon.png', import.meta.url).href,
  shadowUrl: new URL('leaflet/marker-shadow.png', import.meta.url).href,
});

const vehicleIcon = L.divIcon({
  className: 'vehicle-marker',
  html: '<div style="width:32px;height:32px;background:#3b82f6;border:3px solid white;border-radius:50%;box-shadow:0 2px 6px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;font-size:16px">🚌</div>',
  iconSize: [32, 32],
  iconAnchor: [16, 16],
});

export default function ChildTracker({ userId }) {
  const center = getMahikengCenter();
  const [learners, setLearners] = useState([]);
  const [routes, setRoutes] = useState([]);
  const [activeTrips, setActiveTrips] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [newChild, setNewChild] = useState({ name: '', school: '', grade: '' });

  useEffect(() => { loadData(); }, []);

  async function loadData() {
    setLoading(true);
    const [learnersRes, routesRes, tripsRes] = await Promise.all([
      getLearners(userId),
      getTransportRoutes(),
      getActiveTrips(),
    ]);
    setLearners(learnersRes.data || []);
    setRoutes(routesRes.data || []);
    setActiveTrips(tripsRes.data || []);
    setLoading(false);
  }

  async function handleAddChild() {
    if (!newChild.name || !newChild.school) { showToast?.('Name and school required', 'error'); return; }
    const { error } = await registerLearner({ ...newChild, parent_user_token: userId });
    if (error) showToast?.(error, 'error');
    else { showToast?.('Child registered', 'success'); setShowAdd(false); setNewChild({ name: '', school: '', grade: '' }); loadData(); }
  }

  function getTripForRoute(routeId) {
    return activeTrips.find(t => t.route_id === routeId);
  }

  if (loading) return <div className="card animate-pulse"><div className="h-32 bg-gray-200 rounded-lg"></div></div>;

  return (
    <div className="space-y-4">
      {learners.length === 0 ? (
        <div className="card text-center py-8">
          <span className="text-4xl block mb-3">👨‍👩‍👧‍👦</span>
          <p className="text-sm text-gray-600 mb-3">Register your child to track their school transport</p>
          <button onClick={() => setShowAdd(true)} className="btn-primary text-sm">Add Child</button>
        </div>
      ) : (
        <>
          {learners.map(child => {
            const route = routes.find(r => r.id === child.route_id);
            const trip = route ? getTripForRoute(route.id) : null;
            return (
              <div key={child.id} className="card">
                <div className="flex items-center justify-between mb-2">
                  <div>
                    <p className="font-bold text-sm">{child.name}</p>
                    <p className="text-xs text-gray-400">{child.school} — Grade {child.grade}</p>
                  </div>
                  <span className={`badge text-xs ${trip ? (trip.status === 'delayed' ? 'bg-warning-100 text-warning-700' : 'bg-safety-100 text-safety-700') : 'bg-gray-100 text-gray-500'}`}>
                    {trip ? (trip.status === 'delayed' ? '⏰ Delayed' : '🚌 On Route') : 'No active trip'}
                  </span>
                </div>
                {route && <p className="text-xs text-gray-400 mb-2">Route: {route.name} — {route.vehicle_registration}</p>}
                {trip && (
                  <div className="p-2 bg-blue-50 rounded-lg">
                    <p className="text-xs text-blue-700">Trip started {timeAgo(trip.started_at)}</p>
                    {trip.locations?.length > 0 && (
                      <p className="text-xs text-blue-500 mt-1">Last update: {timeAgo(new Date(trip.locations[trip.locations.length - 1].t).toISOString())}</p>
                    )}
                  </div>
                )}
              </div>
            );
          })}
          <button onClick={() => setShowAdd(true)} className="btn-outline text-sm w-full">+ Add Another Child</button>
        </>
      )}

      {/* Live Map */}
      {activeTrips.length > 0 && (
        <div className="card p-0 overflow-hidden">
          <div className="px-3 py-2 border-b border-gray-100">
            <p className="text-xs font-medium text-gray-600">Live Vehicle Positions</p>
          </div>
          <MapContainer center={[center.lat, center.lng]} zoom={13} style={{ height: '200px', width: '100%' }}>
            <TileLayer attribution='&copy; OSM' url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
            {activeTrips.map(trip => {
              const loc = trip.locations?.[trip.locations.length - 1];
              if (!loc) return null;
              return (
                <Marker key={trip.id} position={[loc.lat, loc.lng]} icon={vehicleIcon}>
                  <Popup>
                    <p className="text-sm font-medium">🚌 Trip Active</p>
                    <p className="text-xs text-gray-500">Started {timeAgo(trip.started_at)}</p>
                  </Popup>
                </Marker>
              );
            })}
          </MapContainer>
        </div>
      )}

      {/* Add Child Modal */}
      {showAdd && (
        <div className="fixed inset-0 z-50 bg-black/50 flex items-end justify-center">
          <div className="bg-white rounded-t-3xl w-full max-w-lg p-4 animate-slide-up">
            <h3 className="font-bold text-lg mb-3">Register Child</h3>
            <div className="space-y-3">
              <input type="text" value={newChild.name} onChange={e => setNewChild(p => ({ ...p, name: e.target.value }))} placeholder="Child's name" className="input" />
              <input type="text" value={newChild.school} onChange={e => setNewChild(p => ({ ...p, school: e.target.value }))} placeholder="School name" className="input" />
              <input type="text" value={newChild.grade} onChange={e => setNewChild(p => ({ ...p, grade: e.target.value }))} placeholder="Grade" className="input" />
              <div className="flex gap-2">
                <button onClick={() => setShowAdd(false)} className="btn-outline flex-1">Cancel</button>
                <button onClick={handleAddChild} className="btn-primary flex-1">Register</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

