import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getLearners, getActiveTrips } from '../db/transportApi';
import { useAuth } from '../hooks/useAuth';
import Icon from './Icon';

export default function TransportWidget() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [learnerCount, setLearnerCount] = useState(0);
  const [activeTrip, setActiveTrip] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user?.id) { setLoading(false); return; }
    getLearners(user.id).then(({ data }) => {
      setLearnerCount((data || []).length);
      if (data?.length > 0 && data[0].route_id) {
        getActiveTrips(data[0].route_id).then(({ data: trips }) => {
          setActiveTrip(trips?.[0] || null);
          setLoading(false);
        });
      } else setLoading(false);
    }).catch(() => setLoading(false));
  }, [user]);

  if (loading) return null;

  return (
    <div
      onClick={() => navigate('/edutrans')}
      className={`card cursor-pointer border-l-4 ${
        activeTrip ? 'border-l-safety-500 bg-safety-50' : 'border-l-blue-400 bg-blue-50'
      }`}
    >
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <span className="text-2xl">🚌</span>
          <div>
            <span className="text-sm font-bold text-gray-800">EduTrans</span>
            {activeTrip ? (
              <p className="text-xs text-safety-700">🚌 Trip active — tracking</p>
            ) : learnerCount > 0 ? (
              <p className="text-xs text-gray-500">{learnerCount} child{learnerCount > 1 ? 'ren' : ''} registered</p>
            ) : (
              <p className="text-xs text-gray-500">School transport tracking</p>
            )}
          </div>
        </div>
        <Icon name="chevronRight" className="w-5 h-5 text-gray-400" />
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { registerVolunteer, getVolunteers, deployVolunteer } from '../db/disasterApi';
import { showToast } from '../utils/helpers';

const SKILL_OPTIONS = [
  { key: 'first_aid', label: 'First Aid', icon: '🩺' },
  { key: 'firefighting', label: 'Firefighting', icon: '🧯' },
  { key: 'shelter_management', label: 'Shelter Mgmt', icon: '🏠' },
  { key: 'logistics', label: 'Logistics', icon: '📦' },
  { key: 'counselling', label: 'Counselling', icon: '💬' },
];

export default function VolunteerCoordinator({ userId, isAdmin = false }) {
  const [volunteers, setVolunteers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showRegister, setShowRegister] = useState(false);
  const [form, setForm] = useState({ skills: [], location: '', contact_preference: 'push' });

  useEffect(() => { loadVolunteers(); }, []);

  async function loadVolunteers() {
    setLoading(true);
    const { data } = await getVolunteers();
    setVolunteers(data || []);
    setLoading(false);
  }

  async function handleRegister() {
    if (form.skills.length === 0) { showToast?.('Select at least one skill', 'error'); return; }
    const { error } = await registerVolunteer({ ...form, user_token: userId });
    if (error) showToast?.(error, 'error');
    else { showToast?.('Registered as volunteer!', 'success'); setShowRegister(false); loadVolunteers(); }
  }

  function toggleSkill(skill) {
    setForm(p => ({ ...p, skills: p.skills.includes(skill) ? p.skills.filter(s => s !== skill) : [...p.skills, skill] }));
  }

  return (
    <div className="space-y-4">
      <div className="card">
        <div className="flex items-center justify-between mb-3">
          <h3 className="font-bold text-sm">Community Volunteers</h3>
          <span className="badge bg-safety-100 text-safety-700">{volunteers.filter(v => v.is_available).length} available</span>
        </div>
        {volunteers.length === 0 ? (
          <p className="text-xs text-gray-400 text-center py-4">No volunteers registered yet</p>
        ) : (
          <div className="space-y-2">
            {volunteers.slice(0, 8).map(v => (
              <div key={v.id} className="flex items-center gap-3 p-2 bg-gray-50 rounded-lg">
                <div className={`w-2 h-2 rounded-full ${v.is_available ? 'bg-safety-500' : 'bg-gray-300'}`}></div>
                <div className="flex-1">
                  <div className="flex flex-wrap gap-1">
                    {v.skills?.map(s => {
                      const skill = SKILL_OPTIONS.find(o => o.key === s);
                      return <span key={s} className="text-xs">{skill?.icon || '🔧'}</span>;
                    })}
                  </div>
                  <p className="text-xs text-gray-400">{v.location || 'Mahikeng'}</p>
                </div>
                <span className={`badge text-xs ${v.is_available ? 'bg-safety-100 text-safety-700' : 'bg-gray-100 text-gray-500'}`}>
                  {v.is_available ? 'Available' : 'Unavailable'}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>

      {!showRegister ? (
        <button onClick={() => setShowRegister(true)} className="btn-primary w-full">Register as Volunteer</button>
      ) : (
        <div className="card">
          <h3 className="font-bold text-sm mb-3">Volunteer Registration</h3>
          <div className="space-y-3">
            <div>
              <label className="text-xs font-medium text-gray-700 mb-1.5 block">Skills</label>
              <div className="flex flex-wrap gap-2">
                {SKILL_OPTIONS.map(opt => (
                  <button key={opt.key} onClick={() => toggleSkill(opt.key)}
                    className={`px-3 py-1.5 rounded-lg text-xs font-medium border ${form.skills.includes(opt.key) ? 'bg-civic-50 text-civic-700 border-civic-300' : 'border-gray-200 text-gray-500'}`}>
                    {opt.icon} {opt.label}
                  </button>
                ))}
              </div>
            </div>
            <input type="text" value={form.location} onChange={e => setForm(p => ({ ...p, location: e.target.value }))} placeholder="Your area (e.g. CBD, Montshiwa)" className="input" />
            <select value={form.contact_preference} onChange={e => setForm(p => ({ ...p, contact_preference: e.target.value }))} className="input">
              <option value="push">Push Notification</option>
              <option value="sms">SMS</option>
              <option value="phone">Phone Call</option>
            </select>
            <div className="flex gap-2">
              <button onClick={() => setShowRegister(false)} className="btn-outline flex-1">Cancel</button>
              <button onClick={handleRegister} className="btn-primary flex-1">Register</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { openDB } from 'idb';

const DB_NAME = 'mahikeng-offline';
const DB_VERSION = 3;

let dbPromise = null;

function getDB() {
  if (!dbPromise) {
    dbPromise = openDB(DB_NAME, DB_VERSION, {
      upgrade(db, oldVersion) {
        // Pending civic reports (offline queue)
        if (!db.objectStoreNames.contains('pendingReports')) {
          const reportStore = db.createObjectStore('pendingReports', { keyPath: 'id' });
          reportStore.createIndex('createdAt', 'createdAt');
        }

        // Cached civic reports
        if (!db.objectStoreNames.contains('civicReports')) {
          const store = db.createObjectStore('civicReports', { keyPath: 'id' });
          store.createIndex('status', 'status');
          store.createIndex('category', 'category');
          store.createIndex('createdAt', 'createdAt');
        }

        // Cached safety incidents
        if (!db.objectStoreNames.contains('safetyIncidents')) {
          const store = db.createObjectStore('safetyIncidents', { keyPath: 'id' });
          store.createIndex('createdAt', 'createdAt');
          store.createIndex('incidentType', 'incidentType');
        }

        // Cached map tiles metadata
        if (!db.objectStoreNames.contains('mapCache')) {
          db.createObjectStore('mapCache', { keyPath: 'key' });
        }

        // User data
        if (!db.objectStoreNames.contains('userData')) {
          db.createObjectStore('userData', { keyPath: 'key' });
        }

        // Emergency contacts
        if (!db.objectStoreNames.contains('emergencyContacts')) {
          db.createObjectStore('emergencyContacts', { keyPath: 'id' });
        }

        // Draft reports
        if (!db.objectStoreNames.contains('drafts')) {
          db.createObjectStore('drafts', { keyPath: 'id' });
        }

        // Power module: cached ESP schedule
        if (!db.objectStoreNames.contains('powerCache')) {
          db.createObjectStore('powerCache', { keyPath: 'key' });
        }

        // Power module: business profiles
        if (!db.objectStoreNames.contains('businessProfiles')) {
          const store = db.createObjectStore('businessProfiles', { keyPath: 'id' });
          store.createIndex('userId', 'user_token_id');
        }

        // EduTrans: cached transport data
        if (!db.objectStoreNames.contains('transportCache')) {
          db.createObjectStore('transportCache', { keyPath: 'key' });
        }

        // EduTrans: learner data (encrypted)
        if (!db.objectStoreNames.contains('learnerData')) {
          const store = db.createObjectStore('learnerData', { keyPath: 'id' });
          store.createIndex('parentToken', 'parent_user_token');
        }

        // Disaster Shield: cached warnings and resources
        if (!db.objectStoreNames.contains('disasterCache')) {
          db.createObjectStore('disasterCache', { keyPath: 'key' });
        }

        // Healthcare: cached facilities
        if (!db.objectStoreNames.contains('healthcareCache')) {
          db.createObjectStore('healthcareCache', { keyPath: 'key' });
        }

        // Water Quality: cached readings
        if (!db.objectStoreNames.contains('waterQualityCache')) {
          db.createObjectStore('waterQualityCache', { keyPath: 'key' });
        }

        // Jobs & Tenders: cached listings
        if (!db.objectStoreNames.contains('jobsCache')) {
          db.createObjectStore('jobsCache', { keyPath: 'key' });
        }

        // Marketplace: cached business listings
        if (!db.objectStoreNames.contains('marketplaceCache')) {
          db.createObjectStore('marketplaceCache', { keyPath: 'key' });
        }

        // Documents: cached documents
        if (!db.objectStoreNames.contains('documentsCache')) {
          db.createObjectStore('documentsCache', { keyPath: 'key' });
        }
      },
    });
  }
  return dbPromise;
}

// ============================================================
// PENDING REPORTS (Offline Queue)
// ============================================================
export async function addPendingReport(report) {
  const db = await getDB();
  await db.put('pendingReports', { ...report, createdAt: Date.now(), synced: false });
}

export async function getPendingReports() {
  const db = await getDB();
  return db.getAll('pendingReports');
}

export async function removePendingReport(id) {
  const db = await getDB();
  await db.delete('pendingReports', id);
}

export async function markReportSynced(id) {
  const db = await getDB();
  const report = await db.get('pendingReports', id);
  if (report) {
    report.synced = true;
    await db.put('pendingReports', report);
  }
}

// ============================================================
// CACHED REPORTS
// ============================================================
export async function cacheCivicReports(reports) {
  const db = await getDB();
  const tx = db.transaction('civicReports', 'readwrite');
  for (const report of reports) {
    await tx.store.put(report);
  }
  await tx.done;
}

export async function getCachedCivicReports() {
  const db = await getDB();
  return db.getAll('civicReports');
}

export async function getCachedReportById(id) {
  const db = await getDB();
  return db.get('civicReports', id);
}

// ============================================================
// SAFETY INCIDENTS
// ============================================================
export async function cacheSafetyIncidents(incidents) {
  const db = await getDB();
  const tx = db.transaction('safetyIncidents', 'readwrite');
  for (const incident of incidents) {
    await tx.store.put(incident);
  }
  await tx.done;
}

export async function getCachedSafetyIncidents() {
  const db = await getDB();
  return db.getAll('safetyIncidents');
}

// ============================================================
// USER DATA
// ============================================================
export async function saveUserData(key, value) {
  const db = await getDB();
  await db.put('userData', { key, value, updatedAt: Date.now() });
}

export async function getUserData(key) {
  const db = await getDB();
  const data = await db.get('userData', key);
  return data?.value;
}

// ============================================================
// EMERGENCY CONTACTS
// ============================================================
export async function saveEmergencyContacts(contacts) {
  const db = await getDB();
  await db.put('emergencyContacts', { id: 'contacts', contacts, updatedAt: Date.now() });
}

export async function getEmergencyContacts() {
  const db = await getDB();
  const data = await db.get('emergencyContacts', 'contacts');
  return data?.contacts || [];
}

// ============================================================
// DRAFTS
// ============================================================
export async function saveDraft(draft) {
  const db = await getDB();
  await db.put('drafts', { ...draft, updatedAt: Date.now() });
}

export async function getDrafts() {
  const db = await getDB();
  return db.getAll('drafts');
}

export async function removeDraft(id) {
  const db = await getDB();
  await db.delete('drafts', id);
}

// ============================================================
// POWER MODULE CACHE
// ============================================================
export async function cacheSchedule(schedule) {
  const db = await getDB();
  await db.put('powerCache', { key: 'schedule', data: schedule, cachedAt: Date.now() });
}

export async function getCachedSchedule() {
  const db = await getDB();
  const entry = await db.get('powerCache', 'schedule');
  return entry?.data || null;
}

export async function cachePowerStatus(status) {
  const db = await getDB();
  await db.put('powerCache', { key: 'status', data: status, cachedAt: Date.now() });
}

export async function getCachedPowerStatus() {
  const db = await getDB();
  const entry = await db.get('powerCache', 'status');
  return entry?.data || null;
}

export async function saveBusinessProfile(profile) {
  const db = await getDB();
  await db.put('businessProfiles', profile);
}

export async function getBusinessProfiles() {
  const db = await getDB();
  return db.getAll('businessProfiles');
}

export async function removeBusinessProfile(id) {
  const db = await getDB();
  await db.delete('businessProfiles', id);
}

// ============================================================
// SYNC MANAGER
// ============================================================
export async function syncPendingReports(apiClient) {
  const pending = await getPendingReports();
  const unsynced = pending.filter(r => !r.synced);

  const results = { success: 0, failed: 0 };

  for (const report of unsynced) {
    try {
      await apiClient.submitReport(report);
      await removePendingReport(report.id);
      results.success++;
    } catch (err) {
      console.error(`Failed to sync report ${report.id}:`, err);
      results.failed++;
    }
  }

  return results;
}

// Power Module API — outage reports, business profiles, confirmations
// Dual-mode: Supabase when live, in-memory when mock

import { supabase, isLive } from './supabase';
import { CATEGORY_TO_DEPARTMENT, uuid, delay } from '../utils/helpers';

// In-memory stores (mock mode)
let outageReports = [];
let businessProfiles = [];
let outageConfirmations = [];
let businessAlerts = [];

// ============================================================
// OUTAGE REPORTS (extends civic_reports where category='electricity')
// ============================================================

export async function submitOutageReport(report) {
  const department = 'electricity';

  if (isLive) {
    const { data, error } = await supabase
      .from('civic_reports')
      .insert({
        user_token_id: report.user_token_id || null,
        category: 'electricity',
        department,
        title: report.title || `${report.outage_type === 'scheduled' ? 'Scheduled' : 'Unscheduled'} power outage`,
        description: report.description,
        latitude: report.latitude,
        longitude: report.longitude,
        address: report.address,
        urgency: report.outage_type === 'scheduled' ? 'normal' : 'high',
        photo_urls: report.photo_urls || [],
        outage_type: report.outage_type || 'unknown',
        estimated_restoration: report.estimated_restoration || null,
        is_business_alert: report.is_business_alert || false,
      })
      .select()
      .single();

    if (!error && data) {
      // Trigger business alerts
      await triggerBusinessAlerts(data, report.outage_type);
    }

    return { data, error: error?.message };
  }

  await delay(500);
  const newReport = {
    id: uuid(),
    user_token_id: report.user_token_id || null,
    category: 'electricity',
    department,
    title: report.title || `${report.outage_type === 'scheduled' ? 'Scheduled' : 'Unscheduled'} power outage`,
    description: report.description,
    latitude: report.latitude,
    longitude: report.longitude,
    address: report.address,
    urgency: report.outage_type === 'scheduled' ? 'normal' : 'high',
    status: 'pending',
    outage_type: report.outage_type || 'unknown',
    estimated_restoration: report.estimated_restoration || null,
    is_business_alert: report.is_business_alert || false,
    photo_urls: report.photo_urls || [],
    video_urls: [],
    municipality_response: null,
    resolved_at: null,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };
  outageReports.unshift(newReport);

  // Trigger business alerts (mock)
  await triggerBusinessAlerts(newReport, report.outage_type);

  return { data: newReport, error: null };
}

/**
 * Get all power outage reports (electricity category with outage fields)
 */
export async function getOutageReports(filters = {}) {
  if (isLive) {
    let query = supabase
      .from('civic_reports')
      .select('*')
      .eq('category', 'electricity')
      .order('created_at', { ascending: false });

    if (filters.outageType) query = query.eq('outage_type', filters.outageType);
    if (filters.status) query = query.eq('status', filters.status);
    if (filters.since) query = query.gte('created_at', filters.since);

    const { data, error } = await query;
    return { data: data || [], error: error?.message };
  }

  await delay(300);
  let results = [...outageReports];
  if (filters.outageType) results = results.filter(r => r.outage_type === filters.outageType);
  if (filters.status) results = results.filter(r => r.status === filters.status);
  if (filters.since) results = results.filter(r => r.created_at >= filters.since);
  results.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
  return { data: results, error: null };
}

/**
 * Confirm an outage ("I'm also affected")
 */
export async function confirmOutage(reportId, userId) {
  if (isLive) {
    // Check for existing confirmation
    const { data: existing } = await supabase
      .from('outage_confirmations')
      .select('id')
      .eq('report_id', reportId)
      .eq('user_token_id', userId)
      .single();

    if (existing) return { data: null, error: 'Already confirmed' };

    const { data, error } = await supabase
      .from('outage_confirmations')
      .insert({ report_id: reportId, user_token_id: userId })
      .select()
      .single();

    return { data, error: error?.message };
  }

  await delay(200);
  const existing = outageConfirmations.find(
    c => c.report_id === reportId && c.user_token_id === userId
  );
  if (existing) return { data: null, error: 'Already confirmed' };

  const confirmation = {
    id: uuid(),
    report_id: reportId,
    user_token_id: userId,
    created_at: new Date().toISOString(),
  };
  outageConfirmations.push(confirmation);
  return { data: confirmation, error: null };
}

/**
 * Get confirmation count for a report
 */
export async function getOutageConfirmations(reportId) {
  if (isLive) {
    const { count, error } = await supabase
      .from('outage_confirmations')
      .select('*', { count: 'exact', head: true })
      .eq('report_id', reportId);

    return { count: count || 0, error: error?.message };
  }

  await delay(100);
  const count = outageConfirmations.filter(c => c.report_id === reportId).length;
  return { count, error: null };
}

// ============================================================
// BUSINESS PROFILES
// ============================================================

export async function createBusinessProfile(profile) {
  if (isLive) {
    const { data, error } = await supabase
      .from('business_profiles')
      .insert({
        user_token_id: profile.user_token_id,
        business_name: profile.business_name,
        business_type: profile.business_type,
        phone: profile.phone,
        latitude: profile.latitude,
        longitude: profile.longitude,
        address: profile.address,
        alert_radius_km: profile.alert_radius_km || 2,
        is_active: true,
      })
      .select()
      .single();

    return { data, error: error?.message };
  }

  await delay(400);
  const newProfile = {
    id: uuid(),
    ...profile,
    alert_radius_km: profile.alert_radius_km || 2,
    is_active: true,
    created_at: new Date().toISOString(),
  };
  businessProfiles.push(newProfile);
  return { data: newProfile, error: null };
}

export async function getBusinessProfile(userId) {
  if (isLive) {
    const { data, error } = await supabase
      .from('business_profiles')
      .select('*')
      .eq('user_token_id', userId)
      .single();

    return { data: data || null, error: error?.message };
  }

  await delay(200);
  const profile = businessProfiles.find(p => p.user_token_id === userId);
  return { data: profile || null, error: null };
}

export async function updateBusinessProfile(userId, updates) {
  if (isLive) {
    const { data, error } = await supabase
      .from('business_profiles')
      .update(updates)
      .eq('user_token_id', userId)
      .select()
      .single();

    return { data, error: error?.message };
  }

  await delay(300);
  const idx = businessProfiles.findIndex(p => p.user_token_id === userId);
  if (idx === -1) return { data: null, error: 'Not found' };
  businessProfiles[idx] = { ...businessProfiles[idx], ...updates };
  return { data: businessProfiles[idx], error: null };
}

// ============================================================
// BUSINESS ALERTS
// ============================================================

async function triggerBusinessAlerts(report, outageType) {
  const lat = report.latitude;
  const lng = report.longitude;
  const radiusKm = 2; // default alert radius

  // Find businesses within radius
  let nearbyBusinesses = [];

  if (isLive) {
    // Use PostGIS ST_DWithin for efficient radius search
    const { data } = await supabase.rpc('find_nearby_businesses', {
      lat,
      lng,
      radius_meters: radiusKm * 1000,
    });
    nearbyBusinesses = data || [];
  } else {
    // Mock: find businesses within rough distance
    nearbyBusinesses = businessProfiles.filter(b => {
      if (!b.is_active || !b.latitude || !b.longitude) return false;
      const dlat = b.latitude - lat;
      const dlng = b.longitude - lng;
      const dist = Math.sqrt(dlat * dlat + dlng * dlng) * 111; // rough km
      return dist <= (b.alert_radius_km || radiusKm);
    });
  }

  if (nearbyBusinesses.length === 0) return;

  const alertMessage = outageType === 'scheduled'
    ? `Scheduled load shedding in your area. Check backup generator.`
    : `Unscheduled power outage reported near your business. Move perishables if needed.`;

  // Send alerts
  for (const business of nearbyBusinesses) {
    const alert = {
      id: uuid(),
      business_id: business.id,
      report_id: report.id,
      message: alertMessage,
      outage_type: outageType,
      sent_at: new Date().toISOString(),
    };

    if (isLive) {
      await supabase.from('business_alerts').insert(alert);
    } else {
      businessAlerts.push(alert);
    }

    // Push notification
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification('Mahikeng Power Alert', {
        body: `${business.business_name}: ${alertMessage}`,
        icon: '/icons/icon-192.svg',
        tag: `power-alert-${report.id}`,
      });
    }
  }
}

